const item = $input.first();
const now = new Date();
const iso = now.toISOString();
const stamp = iso.slice(0, 19).split('-').join('').split(':').join('').split('T').join('-');
const random = Math.random().toString(16).slice(2, 8).padEnd(6, '0');
const jobId = stamp + '-' + random;
function trimTrailingSlash(value) {
  let text = String(value || '');
  while (text.endsWith('/')) text = text.slice(0, -1);
  return text;
}
const repoDir = trimTrailingSlash($env.VIDEO_CLIP_REPO_DIR || '/Users/stephenqiu/Desktop/Repository/n8n');
const baseDir = trimTrailingSlash($env.VIDEO_CLIP_JOBS_DIR || repoDir + '/tmp/n8n-video-jobs');
const jobDir = baseDir + '/' + jobId;
return [{ json: { ...item.json, jobId, baseDir, repoDir, jobDir, inputsDir: jobDir + '/inputs', ttsDir: jobDir + '/tts', ttsSegmentsDir: jobDir + '/tts/segments', renderDir: jobDir + '/render' }, binary: item.binary }];

const fs = require('fs');
const item = $input.first();
const binary = item.binary || {};
const keyAliases = {
  coverImage: ['cover_image', 'coverImage'],
  screenshotImage: ['proof_screenshot', 'proofScreenshot'],
  backgroundVideo: ['background_video', 'backgroundVideo']
};
function firstBinaryKey(keys) { return keys.find((key) => binary[key]); }
function cleanText(value) {
  const lf = String.fromCharCode(10);
  const cr = String.fromCharCode(13);
  let text = String(value || '').split(String.fromCharCode(0)).join('').split(cr + lf).join(lf).split(cr).join(lf);
  while (text.includes(lf + lf + lf)) text = text.split(lf + lf + lf).join(lf + lf);
  return text.trim();
}
const uploadKeys = {
  coverImage: firstBinaryKey(keyAliases.coverImage),
  screenshotImage: firstBinaryKey(keyAliases.screenshotImage),
  backgroundVideo: firstBinaryKey(keyAliases.backgroundVideo)
};
for (const [name, key] of Object.entries(uploadKeys)) {
  if (!key) throw new Error('Missing uploaded file: ' + name + '. Accepted field names: ' + keyAliases[name].join(', '));
}
const viewpoint = cleanText(item.json.viewpoint);
if (!viewpoint) throw new Error('viewpoint is required');
const scriptMode = ['single', 'dialogue'].includes(item.json.script_mode) ? item.json.script_mode : 'single';
const scriptStyle = item.json.script_style || 'short_video_commentary';
const selectedVoices = {
  voiceSingle: item.json.voice_single || 'cancan_v2',
  voiceA: item.json.voice_a || 'qingcang_v2',
  voiceB: item.json.voice_b || 'female_general_v2'
};
fs.mkdirSync(item.json.inputsDir, { recursive: true });
fs.mkdirSync(item.json.ttsDir, { recursive: true });
fs.mkdirSync(item.json.ttsSegmentsDir, { recursive: true });
fs.mkdirSync(item.json.renderDir, { recursive: true });
const files = {
  coverImage: item.json.inputsDir + '/cover.png',
  screenshotImage: item.json.inputsDir + '/screenshot.png',
  backgroundVideo: item.json.inputsDir + '/background.mp4',
  scriptText: item.json.inputsDir + '/script.txt',
  generatedScript: item.json.inputsDir + '/generated-script.json',
  llmPrompt: item.json.inputsDir + '/script-prompt.txt',
  llmResponse: item.json.inputsDir + '/script-response.json'
};
for (const [inputName, target] of [['coverImage', files.coverImage], ['screenshotImage', files.screenshotImage], ['backgroundVideo', files.backgroundVideo]]) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, uploadKeys[inputName]);
  fs.writeFileSync(target, buffer);
}
return [{ json: { ...item.json, files, viewpoint, scriptMode, scriptStyle, selectedVoices } }];

const fs = require('fs');
const item = $input.first().json;
const skillPath = item.repoDir + '/tools/video-composer/script-writer/SKILL.md';
if (!fs.existsSync(skillPath)) throw new Error('Script writer skill not found: ' + skillPath);
const llmApiKey = $env.DOUBAO_LLM_API_KEY || $env.ARK_API_KEY;
const llmModel = $env.DOUBAO_LLM_MODEL || $env.ARK_MODEL_NAME;
let llmUrl = $env.DOUBAO_LLM_URL || $env.ARK_API_BASE_URL || 'https://ark.cn-beijing.volces.com/api/v3/chat/completions';
llmUrl = String(llmUrl).trim();
while (llmUrl.endsWith('/')) llmUrl = llmUrl.slice(0, -1);
let llmApiMode = 'chat';
if (llmUrl.endsWith('/responses')) llmApiMode = 'responses';
else if (!llmUrl.endsWith('/chat/completions')) llmUrl += '/chat/completions';
for (const [name, value] of Object.entries({ LLM_API_KEY: llmApiKey, LLM_MODEL: llmModel, LLM_URL: llmUrl })) {
  if (!value) throw new Error('Missing required LLM env var or alias: ' + name);
}
const skill = fs.readFileSync(skillPath, 'utf8');
const targetLength = item.scriptMode === 'dialogue' ? '500-900 Chinese characters' : '350-800 Chinese characters';
const userPrompt = [
  'User viewpoint:', item.viewpoint,
  '',
  'Generation settings:',
  '- mode: ' + item.scriptMode,
  '- style: ' + item.scriptStyle,
  '- targetLength: ' + targetLength,
  '',
  'Return strict JSON following the schema. Do not output Markdown.'
].join('\n');
const messages = [
  { role: 'system', content: skill },
  { role: 'user', content: userPrompt }
];
fs.writeFileSync(item.files.llmPrompt, JSON.stringify({ messages, llmApiMode, llmUrl }, null, 2), 'utf8');
return [{ json: { ...item, llmMessages: messages, llmUrl, llmApiMode } }];

const fs = require('fs');
const { pathToFileURL } = require('url');
const previous = $('Prepare Script Prompt').first().json;
const response = $input.first().json;
const utils = await import(pathToFileURL(previous.repoDir + '/tools/video-composer/workflow-utils.mjs').href);
fs.writeFileSync(previous.files.llmResponse, JSON.stringify(response, null, 2), 'utf8');
function responseText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (typeof value.text === 'string') return value.text;
  if (Array.isArray(value.content)) return value.content.map(responseText).filter(Boolean).join('\n');
  return '';
}
const outputText = Array.isArray(response?.output) ? response.output.map(responseText).filter(Boolean).join('\n') : '';
const content = response?.choices?.[0]?.message?.content || response?.output_text || outputText || response?.message?.content || response?.data?.content || JSON.stringify(response);
const generatedScript = utils.parseGeneratedScript(content, previous.scriptMode);
const generatedScriptText = utils.buildGeneratedScriptText(generatedScript);
fs.writeFileSync(previous.files.generatedScript, JSON.stringify(generatedScript, null, 2), 'utf8');
fs.writeFileSync(previous.files.scriptText, generatedScriptText, 'utf8');
const ttsSegments = utils.buildTtsSegments(generatedScript, previous.selectedVoices, {
  segmentsDir: previous.ttsSegmentsDir,
  fallbackSpeaker: $env.DOUBAO_TTS_VOICE || ''
});
return [{ json: { ...previous, generatedScript, generatedScriptText, generatedScriptTitle: generatedScript.title, generatedScriptSummary: generatedScript.summary, ttsSegments } }];

const fs = require('fs');
const { spawnSync } = require('child_process');
const { pathToFileURL } = require('url');
const item = $input.first().json;
const utils = await import(pathToFileURL(item.repoDir + '/tools/video-composer/workflow-utils.mjs').href);
for (const [name, value] of Object.entries({ DOUBAO_TTS_URL: $env.DOUBAO_TTS_URL, DOUBAO_TTS_API_KEY: $env.DOUBAO_TTS_API_KEY, DOUBAO_TTS_APP_ID: $env.DOUBAO_TTS_APP_ID })) {
  if (!value) throw new Error('Missing required TTS env var: ' + name);
}
function run(command, args, label) {
  const result = spawnSync(command, args, { encoding: 'utf8' });
  if (result.status !== 0) throw new Error(label + ' failed: ' + (result.stderr || result.stdout));
  return result.stdout.trim();
}
function duration(filePath) {
  const output = run('ffprobe', ['-v', 'error', '-show_entries', 'format=duration', '-of', 'default=noprint_wrappers=1:nokey=1', filePath], 'ffprobe');
  const value = Number(output);
  if (!Number.isFinite(value) || value <= 0) throw new Error('Invalid audio duration for ' + filePath + ': ' + output);
  return value;
}
async function requestTts(segment) {
  const response = await fetch($env.DOUBAO_TTS_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Api-App-Id': $env.DOUBAO_TTS_APP_ID,
      'X-Api-Access-Key': $env.DOUBAO_TTS_API_KEY,
      'X-Api-Resource-Id': $env.DOUBAO_TTS_RESOURCE_ID || $env.DOUBAO_TTS_V2_RESOURCE_ID || 'seed-tts-2.0',
      'X-Api-Request-Id': item.jobId + '-' + String(segment.segmentIndex).padStart(3, '0')
    },
    body: JSON.stringify({
      user: { uid: 'n8n-video-clip' },
      req_params: {
        text: segment.text,
        speaker: segment.speaker,
        audio_params: { format: 'mp3', sample_rate: 24000, enable_subtitle: true, enable_timestamp: true }
      }
    })
  });
  const raw = await response.text();
  fs.writeFileSync(segment.responsePath, raw, 'utf8');
  if (!response.ok) throw new Error('TTS segment ' + segment.segmentIndex + ' HTTP ' + response.status + ': ' + raw.slice(0, 500));
  const frames = utils.parseTtsResponseFrames(raw);
  const parsed = utils.extractAudioAndTiming(frames);
  if (parsed.audioBase64Chunks.length === 0) throw new Error('TTS segment ' + segment.segmentIndex + ' returned no audio. role=' + segment.role + ' speaker=' + segment.speaker + ' text=' + segment.text.slice(0, 80));
  const audio = Buffer.concat(parsed.audioBase64Chunks.map((chunk) => Buffer.from(chunk, 'base64')));
  fs.writeFileSync(segment.audioPath, audio);
  fs.writeFileSync(segment.timingPath, JSON.stringify({ frames: parsed.timingFrames }, null, 2), 'utf8');
  return { ...segment, timingFrames: parsed.timingFrames, duration: duration(segment.audioPath), audioSize: audio.length };
}
const segmentMetas = [];
for (const segment of item.ttsSegments) {
  segmentMetas.push(await requestTts(segment));
}
const pauseSeconds = item.scriptMode === 'dialogue' ? Math.max(0, Number($env.VIDEO_CLIP_DIALOGUE_PAUSE_MS || 180) || 0) / 1000 : 0;
const audioPath = item.ttsDir + '/audio.mp3';
const concatInputs = [];
const concatLabels = [];
let inputIndex = 0;
for (let index = 0; index < segmentMetas.length; index += 1) {
  concatInputs.push('-i', segmentMetas[index].audioPath);
  concatLabels.push('[' + inputIndex + ':a]');
  inputIndex += 1;
  if (pauseSeconds > 0 && index < segmentMetas.length - 1) {
    concatInputs.push('-f', 'lavfi', '-t', String(pauseSeconds), '-i', 'anullsrc=channel_layout=stereo:sample_rate=24000');
    concatLabels.push('[' + inputIndex + ':a]');
    inputIndex += 1;
  }
}
run('ffmpeg', ['-y', ...concatInputs, '-filter_complex', concatLabels.join('') + 'concat=n=' + concatLabels.length + ':v=0:a=1[aout]', '-map', '[aout]', '-c:a', 'libmp3lame', '-q:a', '2', audioPath], 'ffmpeg concat');
const mergedTiming = utils.mergeTimingEvents(segmentMetas, { pauseSeconds });
const ttsTimingPath = item.ttsDir + '/timing.json';
fs.writeFileSync(ttsTimingPath, JSON.stringify({ frames: mergedTiming.frames, duration: mergedTiming.duration, pauseSeconds, segments: segmentMetas.map(({ timingFrames, ...meta }) => meta) }, null, 2), 'utf8');
const audio = fs.readFileSync(audioPath);
const ttsAudio = await this.helpers.prepareBinaryData(audio, 'tts-audio.mp3', 'audio/mpeg');
return [{ json: { ...item, audioPath, ttsTimingPath, ttsSegmentMetas: segmentMetas.map(({ timingFrames, ...meta }) => meta), ttsDuration: duration(audioPath), ttsPauseSeconds: pauseSeconds }, binary: { ttsAudio } }];

const fs = require('fs');
const item = $input.first().json;
const job = {
  jobId: item.jobId,
  inputs: {
    coverImage: item.files.coverImage,
    screenshotImage: item.files.screenshotImage,
    backgroundVideo: item.files.backgroundVideo,
    scriptText: item.files.scriptText,
