    subtitles: item.renderDir + '/subtitles.ass',
    ffmpegLog: item.renderDir + '/ffmpeg.log'
  },
  video: { width: 1920, height: 1080, fps: 30, coverDuration: 3, screenshotDuration: 4 },
  layout: {
    coverTop: { x: 80, y: 60, width: 560 },
    screenshotTop: { x: 1280, y: 60, width: 560 },
    cornerImageTreatment: { enabled: true, blur: 2, opacity: 0.82, borderColor: 'white', borderWidth: 6 },
    subtitleBottomMargin: 90
  }
};
const jobPath = item.jobDir + '/job.json';
fs.writeFileSync(jobPath, JSON.stringify(job, null, 2));
return [{ json: { ...item, jobPath, outputVideo: job.output.video, ffmpegLog: job.output.ffmpegLog } }];

const { spawn } = require('child_process');
const item = $input.first().json;
const scriptPath = item.repoDir + '/tools/video-composer/compose-video.mjs';
function runComposer() {
  return new Promise((resolve, reject) => {
    const child = spawn('node', [scriptPath, item.jobPath], { cwd: item.repoDir, stdio: ['ignore', 'pipe', 'pipe'] });
    let stdout = '';
    let stderr = '';
    const maxOutput = 1024 * 1024 * 20;
    child.stdout.on('data', (chunk) => { stdout += chunk.toString('utf8'); if (stdout.length > maxOutput) stdout = stdout.slice(-maxOutput); });
    child.stderr.on('data', (chunk) => { stderr += chunk.toString('utf8'); if (stderr.length > maxOutput) stderr = stderr.slice(-maxOutput); });
    child.on('error', reject);
    child.on('close', (code, signal) => {
      if (code === 0) { resolve({ stdout, stderr }); return; }
      const detail = [stdout, stderr].filter(Boolean).join('\n').trim();
      reject(new Error('Video composer failed with exit code ' + code + (signal ? ' signal ' + signal : '') + (detail ? ':\n' + detail : '')));
    });
  });
}
const result = await runComposer();
return [{ json: { ...item, composerStdout: result.stdout || '', composerStderr: result.stderr || '' } }];

const fs = require('fs');
const item = $('Build Job Config').first().json;
if (!fs.existsSync(item.outputVideo)) throw new Error('Final video was not created: ' + item.outputVideo);
const video = fs.readFileSync(item.outputVideo);
const size = video.length;
if (size === 0) throw new Error('Final video is empty: ' + item.outputVideo);
const binary = { finalVideo: await this.helpers.prepareBinaryData(video, 'final.mp4', 'video/mp4') };
if (item.audioPath && fs.existsSync(item.audioPath)) {
  const audio = fs.readFileSync(item.audioPath);
  binary.ttsAudio = await this.helpers.prepareBinaryData(audio, 'tts-audio.mp3', 'audio/mpeg');
}
return [{ json: { jobId: item.jobId, jobDir: item.jobDir, videoPath: item.outputVideo, audioPath: item.audioPath, ffmpegLog: item.ffmpegLog, size, generatedScriptText: item.generatedScriptText, generatedScriptTitle: item.generatedScriptTitle, generatedScriptSummary: item.generatedScriptSummary, scriptMode: item.scriptMode, selectedVoices: item.selectedVoices, ttsDuration: item.ttsDuration, ttsPauseSeconds: item.ttsPauseSeconds }, binary }];
